/**
 * Bar chart data item interface
 */
export interface AXBarChartData {
  id: string; // Unique identifier for the bar
  label: string; // Label displayed below each bar
  value: number; // Numeric value represented by the bar height
  tooltipLabel?: string; // Optional tooltip label for the bar
  color?: string; // Optional custom color for this specific bar
}
